--
-- Table structure for table `drivers`
--

DROP TABLE IF EXISTS `drivers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `drivers` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `driver_code` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `full_name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vehicle_number` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `license_number` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `vehicle_type` enum('motorbike','three_wheeler','car','van','lorry','truck') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'motorbike',
  `branch_id` bigint unsigned DEFAULT NULL,
  `photo_path` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('available','on_delivery','off_duty','inactive') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'available',
  `license_expiry` date DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `drivers_driver_code_unique` (`driver_code`),
  UNIQUE KEY `drivers_vehicle_unique` (`vehicle_number`,`deleted_at`),
  UNIQUE KEY `drivers_license_unique` (`license_number`,`deleted_at`),
